using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;

// ── Configuration ──────────────────────────────────────────────────────────
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var openAIClient = new OpenAI.OpenAIClient(apiKey);
IChatClient chatClient = new ChatClientBuilder(openAIClient.GetChatClient(modelId))
    .UseFunctionInvocation()
    .Build();

// ── Tools ──────────────────────────────────────────────────────────────────
var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ── Agent loop ─────────────────────────────────────────────────────────────
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍  Researching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to investigate the topic the user
        gives you by searching the web, taking notes on key findings, and finally
        producing a concise summary.

        Workflow:
        1. Search the web for relevant information (use multiple varied queries).
        2. Save important facts, data points, and source URLs as notes.
        3. After gathering enough material (at least 3 searches), retrieve your
           notes and write a well-structured summary with references.

        Always cite sources. Be thorough but concise.
        """),
    new(ChatRole.User, $"Research the following topic and give me a summary: {topic}"),
};

var options = new ChatOptions
{
    Tools = tools,
    ToolMode = ChatToolMode.Auto,
};

var response = await chatClient.GetResponseAsync(messages, options);

Console.WriteLine("─── Research Summary ───────────────────────────────────────");
Console.WriteLine(response.Text);
Console.WriteLine("────────────────────────────────────────────────────────────\n");

// ── Helpers ────────────────────────────────────────────────────────────────
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? throw new InvalidOperationException("A topic is required.")
        : input;
}

// ── Web search tool ────────────────────────────────────────────────────────
static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Search the web for information on a query. Returns a list of result titles, snippets, and URLs.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐  Searching: \"{query}\"");
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var json = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("Abstract", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
            {
                var src = root.TryGetProperty("AbstractURL", out var au) ? au.GetString() : "";
                results.Add($"[Summary] {abstractText} (source: {src})");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                    {
                        var link = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                        results.Add($"• {t} ({link})");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for \"{query}\". Try rephrasing.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

// ── Note-taking tool ───────────────────────────────────────────────────────
class Notebook
{
    private readonly List<(string Fact, string Source)> _notes = [];

    [Description("Save a research note. Use this to record important facts, data points, or quotes along with their source URL.")]
    public string SaveNote(
        [Description("The fact or information to save")] string fact,
        [Description("The source URL or reference")] string source)
    {
        _notes.Add((fact, source));
        Console.WriteLine($"  📝  Note saved ({_notes.Count} total)");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes to use when writing the final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (fact, source) = _notes[i];
            sb.AppendLine($"[{i + 1}] {fact}");
            sb.AppendLine($"    Source: {source}");
        }
        Console.WriteLine($"  📖  Retrieved {_notes.Count} notes");
        return sb.ToString();
    }
}

