         ? throw new InvalidOperationException("A topic is required.")
         : input;
 }

 // ── Web search tool ────────────────────────────────────────────────────────
 static class WebSearchTool
 {
     private static readonly HttpClient Http = new();

     [Description("Search the web for information on a query. Returns a list of result titles, snippets, and URLs.")]
     public static async Task<string> SearchAsync(
         [Description("The search query string")] string query)
     {
         Console.WriteLine($"  🌐  Searching: \"{query}\"");
         try
         {
             var encoded = WebUtility.UrlEncode(query);
             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

             var json = await Http.GetStringAsync(url);
             using var doc = JsonDocument.Parse(json);
             var root = doc.RootElement;

             var results = new List<string>();

             if (root.TryGetProperty("Abstract", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
             {
                 var src = root.TryGetProperty("AbstractURL", out var au) ? au.GetString() : "";
                 results.Add($"[Summary] {abstractText} (source: {src})");
             }

             if (root.TryGetProperty("RelatedTopics", out var topics))
             {
                 foreach (var topic in topics.EnumerateArray().Take(5))
                 {
                     if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                     {
                         var link = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                         results.Add($"• {t} ({link})");
                     }
                 }
             }

             return results.Count > 0
                 ? string.Join("\n", results)
                 : $"No detailed results found for \"{query}\". Try rephrasing.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }
 }

