 class Notebook
 {
     private readonly List<(string Fact, string Source)> _notes = [];

     [Description("Save a research note. Use this to record important facts, data points, or quotes along with their source URL.")]
     public string SaveNote(
         [Description("The fact or information to save")] string fact,
         [Description("The source URL or reference")] string source)
     {
         _notes.Add((fact, source));
         Console.WriteLine($"  📝  Note saved ({_notes.Count} total)");
         return $"Note #{_notes.Count} saved.";
     }

     [Description("Retrieve all saved research notes to use when writing the final summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         var sb = new StringBuilder();
         for (var i = 0; i < _notes.Count; i++)
         {
             var (fact, source) = _notes[i];
             sb.AppendLine($"[{i + 1}] {fact}");
             sb.AppendLine($"    Source: {source}");
         }
         Console.WriteLine($"  📖  Retrieved {_notes.Count} notes");
         return sb.ToString();
     }
